1	/******************************************************************************
2	 * This file introduces a data structure to store fabric-dependent bitstream
3	 *information
4	 *
5	 * General concept
6	 * ---------------
7	 * The idea is to create a unified data structure that stores the sequence of
8	 *configuration bit in the architecture bitstream database as well as the
9	 *information (such as address of each bit) required by a specific configuration
10	 *protocol
11	 *
12	 * Cross-reference
13	 * ---------------
14	 * By using the link between ArchBitstreamManager and FabricBitstream,
15	 * we can build a sequence of configuration bits to fit different configuration
16	 *protocols.
17	 *
18	 *     +----------------------+                 +-------------------+
19	 *     |                      |   ConfigBitId   |                   |
20	 *     | ArchBitstreamManager |---------------->|  FabricBitstream  |
21	 *     |                      |                 |                   |
22	 *     +----------------------+                 +-------------------+
23	 *
24	 * Restrictions:
25	 * 1. Each block inside BitstreamManager should have only 1 parent block
26	 *    and multiple child block
27	 * 2. Each bit inside BitstreamManager should have only 1 parent block
28	 *
29	 ******************************************************************************/
30	#ifndef FABRIC_BITSTREAM_H
31	#define FABRIC_BITSTREAM_H
32	
33	#include <cstdint>
34	#include <unordered_map>
35	#include <unordered_set>
36	#include <vector>
37	
38	#include "bitstream_manager_fwd.h"
39	#include "fabric_bitstream_fwd.h"
40	#include "vtr_vector.h"
41	
42	/* begin namespace openfpga */
43	namespace openfpga {
44	
45	// Use uint32_t (maximum of 4Gigs) is good enough, we have BL and WL,
46	// combination of both hold up to 18 quintillion of configuration bits (+ dont
47	// care)
48	typedef uint32_t fabric_size_t;
49	struct fabric_bit_data {
50	  fabric_bit_data(fabric_size_t r, fabric_size_t b, fabric_size_t w, bool bi)
51	    : region(r), bl(b), wl(w), bit(bi) {}
52	  const fabric_size_t region = 0;
53	  const fabric_size_t bl = 0;
54	  const fabric_size_t wl = 0;
55	  const bool bit = false;
56	};
57	struct fabric_blwl_length {
58	  fabric_blwl_length(fabric_size_t b, fabric_size_t w) : bl(b), wl(w) {}
59	  const fabric_size_t bl = 0;
60	  const fabric_size_t wl = 0;
61	};
62	
63	/*
64	  This class arrange Memory Bank databae in a compact way
65	*/
66	struct FabricBitstreamMemoryBank {
67	  void add_bit(const fabric_size_t& bit_id, const fabric_size_t& region_id,
68	               const fabric_size_t& bl, const fabric_size_t& wl,
69	               const fabric_size_t& bl_addr_size,
70	               const fabric_size_t& wl_addr_size, bool bit);
71	  void fast_configuration(const bool& fast, const bool& bit_value_to_skip);
72	  fabric_size_t get_longest_effective_wl_count() const;
73	  fabric_size_t get_total_bl_addr_size() const;
74	  fabric_size_t get_total_wl_addr_size() const;
75	
76	  /*************************
77	   * All the database (except fabric_bit_datas) is sorted by region
78	   *  1. The very first layer of vector is region
79	   * For the datas and masks
80	   *  1. They are sorted by WL, hence second layer is WL
81	   *  2. Last layer is BL data stored in vector of uint8_t
82	   *  3. Each uint8_t will store up-to 8 configuration bit info
83	   **************************/
84	  // Store the BL WL of each region
85	  std::vector<fabric_blwl_length> blwl_lengths;
86	  // Store config ID raw data. Not used by bitstream generation
87	  // Used by XML generation
88	  /*
89	      fabric_bit_datas[Bit #0] = (region, bl, wl)
90	      fabric_bit_datas[Bit #1] = (region, bl, wl)
91	      fabric_bit_datas[Bit #2] = (region, bl, wl)
92	    */
93	  std::vector<fabric_bit_data> fabric_bit_datas;
94	  // 100K LE FPGA only need few mega bytes
95	  /*
96	    datas represent the Din value of a given WL and BL (1bit)
97	      datas[region #0][wl #0] = std::vector<uint8_t> to represent BLs
98	        where uint8_t #0 = MSB{ BL#7, BL#6, .... BL #1, BL #0 } LSB
99	        where uint8_t #1 = MSB{ BL#15, BL#14, .... BL #9, BL #8 } LSB
100	      datas[region #0][wl #1] = std::vector<uint8_t> to represent BLs
101	      datas[region #0][wl #2] = std::vector<uint8_t> to represent BLs
102	      ......
103	      datas[region #0][wl #n-1] = std::vector<uint8_t> to represent BLs
104	      ......
105	      datas[region #1][wl #0] = std::vector<uint8_t> to represent BLs
106	      datas[region #1][wl #1] = std::vector<uint8_t> to represent BLs
107	      ......
108	  */
109	  std::vector<std::vector<std::vector<uint8_t>>> datas;
110	  /*
111	    masks has same structure as datas
112	    but masks presents data that being used
113	    for exampe:
114	      if mask's uint8_t #0 value = 0x41 it means for this WL
115	        a. BL #0 is being used, and its Din is recoreded in datas
116	        b. BL #6 is being used, and its Din is recoreded in datas
117	        c. Other BLs #1, 2, 3, 4, 5, 7 are don't care bit (not being used)
118	  */
119	  std::vector<std::vector<std::vector<uint8_t>>> masks;
120	  // This track which WL to skip because of fast configuration
121	  std::vector<std::vector<fabric_size_t>> wls_to_skip;
122	};
123	
124	class FabricBitstream {
125	 public: /* Type implementations */
126	  /*
127	   * This class (forward delcared above) is a template used to represent a
128	   * lazily calculated iterator of the specified ID type. The key assumption
129	   * made is that the ID space is contiguous and can be walked by incrementing
130	   * the underlying ID value. To account for invalid IDs, it keeps a reference
131	   * to the invalid ID set and returns ID::INVALID() for ID values in the set.
132	   *
133	   * It is used to lazily create an iteration range (e.g. as returned by
134	   * RRGraph::edges() RRGraph::nodes()) just based on the count of allocated
135	   * elements (i.e. RRGraph::num_nodes_ or RRGraph::num_edges_), and the set of
136	   * any invalid IDs (i.e. RRGraph::invalid_node_ids_,
137	   * RRGraph::invalid_edge_ids_).
138	   */
139	  template <class ID>
140	  class lazy_id_iterator
141	    : public std::iterator<std::bidirectional_iterator_tag, ID> {
142	   public:
143	    // Since we pass ID as a template to std::iterator we need to use an
144	    // explicit 'typename' to bring the value_type and iterator names into scope
145	    typedef
146	      typename std::iterator<std::bidirectional_iterator_tag, ID>::value_type
147	        value_type;
148	    typedef
149	      typename std::iterator<std::bidirectional_iterator_tag, ID>::iterator
150	        iterator;
151	
152	    lazy_id_iterator(value_type init, const std::unordered_set<ID>& invalid_ids)
153	      : value_(init), invalid_ids_(invalid_ids) {}
154	
155	    // Advance to the next ID value
156	    iterator operator++() {
157	      value_ = ID(size_t(value_) + 1);
158	      return *this;
159	    }
160	
161	    // Advance to the previous ID value
162	    iterator operator--() {
163	      value_ = ID(size_t(value_) - 1);
164	      return *this;
165	    }
166	
167	    // Dereference the iterator
168	    value_type operator*() const {
169	      return (invalid_ids_.count(value_)) ? ID::INVALID() : value_;
170	    }
171	
172	    friend bool operator==(const lazy_id_iterator<ID> lhs,
173	                           const lazy_id_iterator<ID> rhs) {
174	      return lhs.value_ == rhs.value_;
175	    }
176	    friend bool operator!=(const lazy_id_iterator<ID> lhs,
177	                           const lazy_id_iterator<ID> rhs) {
178	      return !(lhs == rhs);
179	    }
180	
181	   private:
182	    value_type value_;
183	    const std::unordered_set<ID>& invalid_ids_;
184	  };
185	
186	 public: /* Types and ranges */
187	  // Lazy iterator utility forward declaration
188	  template <class ID>
189	  class lazy_id_iterator;
190	
191	  typedef lazy_id_iterator<FabricBitId> fabric_bit_iterator;
192	  typedef lazy_id_iterator<FabricBitRegionId> fabric_bit_region_iterator;
193	
194	  typedef vtr::Range<fabric_bit_iterator> fabric_bit_range;
195	  typedef vtr::Range<fabric_bit_region_iterator> fabric_bit_region_range;
196	
197	 public: /* Public constructor */
198	  FabricBitstream();
199	
200	 public: /* Public aggregators */
201	  /* Find all the configuration bits */
202	  size_t num_bits() const;
203	  fabric_bit_range bits() const;
204	
205	  /* Find all the configuration regions */
206	  size_t num_regions() const;
207	  fabric_bit_region_range regions() const;
208	  std::vector<FabricBitId> region_bits(
209	    const FabricBitRegionId& region_id) const;
210	
211	 public: /* Public Accessors */
212	  /* Find the configuration bit id in architecture bitstream database */
213	  ConfigBitId config_bit(const FabricBitId& bit_id) const;
214	
215	  /* Find the address of bitstream */
216	  std::vector<char> bit_address(const FabricBitId& bit_id) const;
217	  std::vector<char> bit_bl_address(const FabricBitId& bit_id) const;
218	  std::vector<char> bit_wl_address(const FabricBitId& bit_id) const;
219	
220	  /* Find the data-in of bitstream */
221	  char bit_din(const FabricBitId& bit_id) const;
222	
223	  /* Check if address data is accessible or not*/
224	  bool use_address() const;
225	  bool use_wl_address() const;
226	
227	  const FabricBitstreamMemoryBank& memory_bank_info(
228	    const bool& fast = false, const bool& bit_value_to_skip = false) const;
229	
230	 public: /* Public Mutators */
231	  /* Reserve config bits */
232	  void reserve_bits(const size_t& num_bits);
233	
234	  /* Add a new configuration bit to the bitstream manager */
235	  FabricBitId add_bit(const ConfigBitId& config_bit_id);
236	
237	  void set_bit_address(const FabricBitId& bit_id,
238	                       const std::vector<char>& address,
239	                       const bool& tolerant_short_address = false);
240	
241	  void set_bit_bl_address(const FabricBitId& bit_id,
242	                          const std::vector<char>& address,
243	                          const bool& tolerant_short_address = false);
244	
245	  void set_bit_wl_address(const FabricBitId& bit_id,
246	                          const std::vector<char>& address,
247	                          const bool& tolerant_short_address = false);
248	
249	  void set_bit_din(const FabricBitId& bit_id, const char& din);
250	
251	  /* Reserve regions */
252	  void reserve_regions(const size_t& num_regions);
253	
254	  /* Add a new configuration region */
255	  FabricBitRegionId add_region();
256	
257	  void add_bit_to_region(const FabricBitRegionId& region_id,
258	                         const FabricBitId& bit_id);
259	
260	  /* Reserve bits by region */
261	  void reverse_region_bits(const FabricBitRegionId& region_id);
262	
263	  /* Reverse bit sequence of the fabric bitstream
264	   * This is required by configuration chain protocol
265	   */
266	  void reverse();
267	
268	  /* Enable the use of address-related data
269	   * When this is enabled, data allocation will be applied to these data
270	   * and users can access/modify the data
271	   * Otherwise, it will NOT be allocated and accessible.
272	   *
273	   * This function is only applicable before any bits are added
274	   */
275	  void set_use_address(const bool& enable);
276	  void set_address_length(const size_t& length);
277	  void set_bl_address_length(const size_t& length);
278	
279	  /*
280	    This is setting memory bank protocol in a more efficient way
281	    Instead of building lengthy BL/WL bits of database (BL or Wl could be in
282	    thousand bits of size), a small device like 100K LE (compared to other
283	    vendors offer) might end up using tens of gig bytes.
284	  */
285	  void set_memory_bank_info(const FabricBitId& bit_id,
286	                            const FabricBitRegionId& region_id,
287	                            const size_t& bl, const size_t& wl,
288	                            const size_t& bl_addr_size,
289	                            const size_t& wl_addr_size, bool bit);
290	
291	  /* Enable the use of WL-address related data
292	   * Same priniciple as the set_use_address()
293	   */
294	  void set_use_wl_address(const bool& enable);
295	  void set_wl_address_length(const size_t& length);
296	
297	 public: /* Public Validators */
298	  bool valid_bit_id(const FabricBitId& bit_id) const;
299	  bool valid_region_id(const FabricBitRegionId& bit_id) const;
300	
301	 private: /* Private APIs */
302	  uint64_t encode_address_1bits(const std::vector<char>& address) const;
303	  uint64_t encode_address_xbits(const std::vector<char>& address) const;
304	  std::vector<char> decode_address_bits(const size_t& bit1, const size_t& bitx,
305	                                        const size_t& addr_len) const;
306	
307	 private: /* Internal data */
308	  /* Unique id of a region in the Bitstream */
309	  size_t num_regions_;
310	  std::unordered_set<FabricBitRegionId> invalid_region_ids_;
311	  vtr::vector<FabricBitRegionId, std::vector<FabricBitId>> region_bit_ids_;
312	
313	  /* Unique id of a bit in the Bitstream */
314	  size_t num_bits_;
315	  std::unordered_set<FabricBitId> invalid_bit_ids_;
316	  vtr::vector<FabricBitId, ConfigBitId> config_bit_ids_;
317	
318	  /* Flags to indicate if the addresses and din should be enabled */
319	  bool use_address_;
320	  bool use_wl_address_;
321	
322	  size_t address_length_;
323	  size_t wl_address_length_;
324	
325	  /* Address bits: this is designed for memory decoders
326	   * Here we store the encoded format of the address, and decoded to binary
327	   * format which can be loaded to the configuration protocol directly
328	   *
329	   * Encoding strategy is as follows:
330	   * - An address bit which may contain '0', '1', 'x'. For example
331	   *     101x1
332	   * - The string can be encoded into two integer numbers:
333	   *   - bit-one number: which encodes the '0' and '1' bits into a number. For
334	   * example, 101x1 -> 10101 -> 21
335	   *   - bit-x number: which encodes the 'x' bits into a number. For example,
336	   *       101x1 -> 00010 -> 2
337	   *
338	   * Note that when the length of address vector is more than 64, we use
339	   * multiple 64-bit data to store the encoded values
340	   */
341	  vtr::vector<FabricBitId, std::vector<uint64_t>> bit_address_1bits_;
342	  vtr::vector<FabricBitId, std::vector<uint64_t>> bit_address_xbits_;
343	  vtr::vector<FabricBitId, std::vector<uint64_t>> bit_wl_address_1bits_;
344	  vtr::vector<FabricBitId, std::vector<uint64_t>> bit_wl_address_xbits_;
345	
346	  /* Data input (Din) bits: this is designed for memory decoders */
347	  vtr::vector<FabricBitId, char> bit_dins_;
348	
349	  /* New way of dealing with memory bank protocol - fast and compact */
350	  FabricBitstreamMemoryBank memory_bank_data_;
351	};
352	
353	} /* end namespace openfpga */
354	
355	#endif
