25	/********************************************************************
26	 * This function aims to build a bitstream for configuration chain-like protocol
27	 * It will walk through all the configurable children under a module
28	 * in a recursive way, following a Depth-First Search (DFS) strategy
29	 * For each configuration child, we use its instance name as a key to spot the
30	 * configuration bits in bitstream manager.
31	 * Note that it is guarentee that the instance name in module manager is
32	 * consistent with the block names in bitstream manager
33	 * We use this link to reorganize the bitstream in the sequence of memories as
34	 *we stored in the configurable_children() and configurable_child_instances() of
35	 *each module of module manager
36	 *******************************************************************/
37	static void rec_build_module_fabric_dependent_chain_bitstream(
38	  const BitstreamManager& bitstream_manager, const ConfigBlockId& parent_block,
39	  const ModuleManager& module_manager, const ModuleId& top_module,
40	  const ModuleId& parent_module, const ConfigRegionId& config_region,
41	  FabricBitstream& fabric_bitstream,
42	  const FabricBitRegionId& fabric_bitstream_region, const bool& verbose) {
43	  /* Depth-first search: if we have any children in the parent_block,
44	   * we dive to the next level first!
45	   */
46	  if (0 < bitstream_manager.block_children(parent_block).size()) {
47	    if (parent_module == top_module) {
48	      for (size_t child_id = 0; child_id < module_manager
49	                                             .region_configurable_children(
50	                                               parent_module, config_region)
51	                                             .size();
52	           ++child_id) {
53	        ModuleId child_module = module_manager.region_configurable_children(
54	          parent_module, config_region)[child_id];
55	        size_t child_instance =
56	          module_manager.region_configurable_child_instances(
57	            parent_module, config_region)[child_id];
58	        /* Get the instance name and ensure it is not empty */
59	        std::string instance_name = module_manager.instance_name(
60	          parent_module, child_module, child_instance);
61	
62	        /* Find the child block that matches the instance name! */
63	        ConfigBlockId child_block =
64	          bitstream_manager.find_child_block(parent_block, instance_name);
65	        /* We must have one valid block id! */
66	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
67	
68	        /* Go recursively */
69	        rec_build_module_fabric_dependent_chain_bitstream(
70	          bitstream_manager, child_block, module_manager, top_module,
71	          child_module, config_region, fabric_bitstream,
72	          fabric_bitstream_region, verbose);
73	      }
74	    } else {
75	      for (size_t child_id = 0;
76	           child_id <
77	           module_manager
78	             .configurable_children(
79	               parent_module, ModuleManager::e_config_child_type::PHYSICAL)
80	             .size();
81	           ++child_id) {
82	        ModuleId child_module = module_manager.configurable_children(
83	          parent_module,
84	          ModuleManager::e_config_child_type::PHYSICAL)[child_id];
85	        size_t child_instance = module_manager.configurable_child_instances(
86	          parent_module,
87	          ModuleManager::e_config_child_type::PHYSICAL)[child_id];
88	        /* Get the instance name and ensure it is not empty */
89	        std::string instance_name = module_manager.instance_name(
90	          parent_module, child_module, child_instance);
91	
92	        /* Find the child block that matches the instance name! */
93	        ConfigBlockId child_block =
94	          bitstream_manager.find_child_block(parent_block, instance_name);
95	        VTR_LOGV(verbose,
96	                 "Try to find a configurable block corresponding to module "
97	                 "'%s' in FPGA fabric under its parent block '%s'\n",
98	                 instance_name.c_str(),
99	                 bitstream_manager.block_name(parent_block).c_str());
100	        /* We must have one valid block id! */
101	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
102	
103	        /* Go recursively */
104	        rec_build_module_fabric_dependent_chain_bitstream(
105	          bitstream_manager, child_block, module_manager, top_module,
106	          child_module, config_region, fabric_bitstream,
107	          fabric_bitstream_region, verbose);
108	      }
109	    }
110	    /* Ensure that there should be no configuration bits in the parent block */
111	    VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
112	  }
113	
114	  /* Note that, reach here, it means that this is a leaf node.
115	   * We add the configuration bits to the fabric_bitstream,
116	   * And then, we can return
117	   */
118	  for (const ConfigBitId& config_bit :
119	       bitstream_manager.block_bits(parent_block)) {
120	    FabricBitId fabric_bit = fabric_bitstream.add_bit(config_bit);
121	    fabric_bitstream.add_bit_to_region(fabric_bitstream_region, fabric_bit);
122	  }
123	}
124	
125	/********************************************************************
126	 * This function aims to build a bitstream for memory-bank protocol
127	 * It will walk through all the configurable children under a module
128	 * in a recursive way, following a Depth-First Search (DFS) strategy
129	 * For each configuration child, we use its instance name as a key to spot the
130	 * configuration bits in bitstream manager.
131	 * Note that it is guarentee that the instance name in module manager is
132	 * consistent with the block names in bitstream manager
133	 * We use this link to reorganize the bitstream in the sequence of memories as
134	 *we stored in the configurable_children() and configurable_child_instances() of
135	 *each module of module manager
136	 *
137	 * In such configuration organization, each memory cell has an unique index.
138	 * Using this index, we can infer the address codes for both BL and WL decoders.
139	 * Note that, we must get the number of BLs and WLs before using this function!
140	 *******************************************************************/
141	static void rec_build_module_fabric_dependent_memory_bank_bitstream(
142	  const BitstreamManager& bitstream_manager, const ConfigBlockId& parent_block,
143	  const ModuleManager& module_manager, const ModuleId& top_module,
144	  const ModuleId& parent_module, const ConfigRegionId& config_region,
145	  const size_t& bl_addr_size, const size_t& wl_addr_size, const size_t& num_bls,
146	  const size_t& num_wls, size_t& cur_mem_index,
147	  FabricBitstream& fabric_bitstream,
148	  const FabricBitRegionId& fabric_bitstream_region) {
149	  /* Depth-first search: if we have any children in the parent_block,
150	   * we dive to the next level first!
151	   */
152	  if (0 < bitstream_manager.block_children(parent_block).size()) {
153	    /* For top module:
154	     *   - Use regional configurable children
155	     *   - we will skip the two decoders at the end of the configurable children
156	     * list
157	     */
158	    if (parent_module == top_module) {
159	      std::vector<ModuleId> configurable_children =
160	        module_manager.region_configurable_children(parent_module,
161	                                                    config_region);
162	
163	      VTR_ASSERT(2 <= configurable_children.size());
164	      size_t num_configurable_children = configurable_children.size() - 2;
165	
166	      /* Early exit if there is no configurable children */
167	      if (0 == num_configurable_children) {
168	        /* Ensure that there should be no configuration bits in the parent block
169	         */
170	        VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
171	        return;
172	      }
173	
174	      for (size_t child_id = 0; child_id < num_configurable_children;
175	           ++child_id) {
176	        ModuleId child_module = configurable_children[child_id];
177	        size_t child_instance =
178	          module_manager.region_configurable_child_instances(
179	            parent_module, config_region)[child_id];
180	
181	        /* Get the instance name and ensure it is not empty */
182	        std::string instance_name = module_manager.instance_name(
183	          parent_module, child_module, child_instance);
184	
185	        /* Find the child block that matches the instance name! */
186	        ConfigBlockId child_block =
187	          bitstream_manager.find_child_block(parent_block, instance_name);
188	        /* We must have one valid block id! */
189	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
190	
191	        /* Go recursively */
192	        rec_build_module_fabric_dependent_memory_bank_bitstream(
193	          bitstream_manager, child_block, module_manager, top_module,
194	          child_module, config_region, bl_addr_size, wl_addr_size, num_bls,
195	          num_wls, cur_mem_index, fabric_bitstream, fabric_bitstream_region);
196	      }
197	    } else {
198	      VTR_ASSERT(parent_module != top_module);
199	      /* For other modules:
200	       *   - Use configurable children directly
201	       *   - no need to exclude decoders as they are not there
202	       */
203	      std::vector<ModuleId> configurable_children =
204	        module_manager.configurable_children(
205	          parent_module, ModuleManager::e_config_child_type::PHYSICAL);
206	
207	      size_t num_configurable_children = configurable_children.size();
208	
209	      /* Early exit if there is no configurable children */
210	      if (0 == num_configurable_children) {
211	        /* Ensure that there should be no configuration bits in the parent block
212	         */
213	        VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
214	        return;
215	      }
216	
217	      for (size_t child_id = 0; child_id < num_configurable_children;
218	           ++child_id) {
219	        ModuleId child_module = configurable_children[child_id];
220	        size_t child_instance = module_manager.configurable_child_instances(
221	          parent_module,
222	          ModuleManager::e_config_child_type::PHYSICAL)[child_id];
223	
224	        /* Get the instance name and ensure it is not empty */
225	        std::string instance_name = module_manager.instance_name(
226	          parent_module, child_module, child_instance);
227	
228	        /* Find the child block that matches the instance name! */
229	        ConfigBlockId child_block =
230	          bitstream_manager.find_child_block(parent_block, instance_name);
231	        /* We must have one valid block id! */
232	        VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
233	
234	        /* Go recursively */
235	        rec_build_module_fabric_dependent_memory_bank_bitstream(
236	          bitstream_manager, child_block, module_manager, top_module,
237	          child_module, config_region, bl_addr_size, wl_addr_size, num_bls,
238	          num_wls, cur_mem_index, fabric_bitstream, fabric_bitstream_region);
239	      }
240	    }
241	    /* Ensure that there should be no configuration bits in the parent block */
242	    VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
243	
244	    return;
245	  }
246	
247	  /* Note that, reach here, it means that this is a leaf node.
248	   * We add the configuration bits to the fabric_bitstream,
249	   * And then, we can return
250	   */
251	  for (const ConfigBitId& config_bit :
252	       bitstream_manager.block_bits(parent_block)) {
253	    FabricBitId fabric_bit = fabric_bitstream.add_bit(config_bit);
254	
255	    /* Find BL address */
256	    size_t cur_bl_index = std::floor(cur_mem_index / num_bls);
257	    std::vector<char> bl_addr_bits_vec =
258	      itobin_charvec(cur_bl_index, bl_addr_size);
259	
260	    /* Find WL address */
261	    size_t cur_wl_index = cur_mem_index % num_wls;
262	    std::vector<char> wl_addr_bits_vec =
263	      itobin_charvec(cur_wl_index, wl_addr_size);
264	
265	    /* Set BL address */
266	    fabric_bitstream.set_bit_bl_address(fabric_bit, bl_addr_bits_vec);
267	
268	    /* Set WL address */
269	    fabric_bitstream.set_bit_wl_address(fabric_bit, wl_addr_bits_vec);
270	
271	    /* Set data input */
272	    fabric_bitstream.set_bit_din(fabric_bit,
273	                                 bitstream_manager.bit_value(config_bit));
274	
275	    /* Add the bit to the region */
276	    fabric_bitstream.add_bit_to_region(fabric_bitstream_region, fabric_bit);
277	
278	    /* Increase the memory index */
279	    cur_mem_index++;
280	  }
281	}
282	
283	/********************************************************************
284	 * This function aims to build a bitstream for frame-based configuration
285	 *protocol It will walk through all the configurable children under a module in
286	 *a recursive way, following a Depth-First Search (DFS) strategy For each
287	 *configuration child, we use its instance name as a key to spot the
288	 * configuration bits in bitstream manager.
289	 * Note that it is guarenteed that the instance name in module manager is
290	 * consistent with the block names in bitstream manager
291	 * We use this link to reorganize the bitstream in the sequence of memories as
292	 *we stored in the configurable_children() and configurable_child_instances() of
293	 *each module of module manager
294	 *
295	 * For each configuration bits, we will infer its address based on
296	 *  - the child index in the configurable children list of current module
297	 *  - the child index of all the parent modules in their configurable children
298	 *list until the top in the hierarchy
299	 *
300	 * The address will be organized as follows:
301	 *  <Address_in_top> ... <Address_in_parent_module>
302	 * The address will be decoded to a binary format
303	 *
304	 * For each configuration bit, the data_in for the frame-based decoders will be
305	 * the same as the configuration bit in bitstream manager.
306	 *******************************************************************/
307	static void rec_build_module_fabric_dependent_frame_bitstream(
308	  const BitstreamManager& bitstream_manager,
309	  const std::vector<ConfigBlockId>& parent_blocks,
310	  const ModuleManager& module_manager, const ModuleId& top_module,
311	  const ConfigRegionId& config_region,
312	  const std::vector<ModuleId>& parent_modules,
313	  const std::vector<char>& addr_code, const char& bitstream_dont_care_char,
314	  FabricBitstream& fabric_bitstream,
315	  FabricBitRegionId& fabric_bitstream_region) {
316	  /* Depth-first search: if we have any children in the parent_block,
317	   * we dive to the next level first!
318	   */
319	  if (0 < bitstream_manager.block_children(parent_blocks.back()).size()) {
320	    const ConfigBlockId& parent_block = parent_blocks.back();
321	    const ModuleId& parent_module = parent_modules.back();
322	
323	    std::vector<ModuleId> configurable_children;
324	    std::vector<size_t> configurable_child_instances;
325	    if (top_module == parent_module) {
326	      configurable_children = module_manager.region_configurable_children(
327	        parent_module, config_region);
328	      configurable_child_instances =
329	        module_manager.region_configurable_child_instances(parent_module,
330	                                                           config_region);
331	    } else {
332	      VTR_ASSERT(top_module != parent_module);
333	      configurable_children = module_manager.configurable_children(
334	        parent_module, ModuleManager::e_config_child_type::PHYSICAL);
335	      configurable_child_instances =
336	        module_manager.configurable_child_instances(
337	          parent_module, ModuleManager::e_config_child_type::PHYSICAL);
338	    }
339	
340	    size_t num_configurable_children = configurable_children.size();
341	
342	    size_t max_child_addr_code_size = 0;
343	    bool add_addr_code = true;
344	    ModuleId decoder_module = ModuleId::INVALID();
345	
346	    /* Early exit if there is no configurable children */
347	    if (0 == num_configurable_children) {
348	      /* Ensure that there should be no configuration bits in the parent block
349	       */
350	      VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
351	      return;
352	    }
353	
354	    /* For only 1 configurable child,
355	     * there is no frame decoder here, we can pass on addr code directly
356	     */
357	    if (1 == num_configurable_children) {
358	      add_addr_code = false;
359	    } else {
360	      /* For more than 2 children, there is a decoder in the tail of the list
361	       * We will not decode that, but will access the address size from that
362	       * module So, we reduce the number of children by 1
363	       */
364	      VTR_ASSERT(2 < num_configurable_children);
365	      num_configurable_children--;
366	      decoder_module = configurable_children.back();
367	
368	      /* The max address code size is the max address code size of all the
369	       * configurable children in all the regions
370	       */
371	      for (const ModuleId& child_module : module_manager.configurable_children(
372	             parent_module, ModuleManager::e_config_child_type::PHYSICAL)) {
373	        /* Bypass any decoder module (which no configurable children */
374	        if (module_manager
375	              .configurable_children(
376	                child_module, ModuleManager::e_config_child_type::PHYSICAL)
377	              .empty()) {
378	          continue;
379	        }
380	        const ModulePortId& child_addr_port_id =
381	          module_manager.find_module_port(
382	            child_module, std::string(DECODER_ADDRESS_PORT_NAME));
383	        const BasicPort& child_addr_port =
384	          module_manager.module_port(child_module, child_addr_port_id);
385	        max_child_addr_code_size =
386	          std::max(child_addr_port.get_width(), max_child_addr_code_size);
387	      }
388	    }
389	
390	    for (size_t child_id = 0; child_id < num_configurable_children;
391	         ++child_id) {
392	      ModuleId child_module = configurable_children[child_id];
393	      size_t child_instance = configurable_child_instances[child_id];
394	      /* Get the instance name and ensure it is not empty */
395	      std::string instance_name = module_manager.instance_name(
396	        parent_module, child_module, child_instance);
397	
398	      /* Find the child block that matches the instance name! */
399	      ConfigBlockId child_block =
400	        bitstream_manager.find_child_block(parent_block, instance_name);
401	      /* We must have one valid block id! */
402	      VTR_ASSERT(true == bitstream_manager.valid_block_id(child_block));
403	
404	      /* Pass on the list of blocks, modules and address lists */
405	      std::vector<ConfigBlockId> child_blocks = parent_blocks;
406	      child_blocks.push_back(child_block);
407	
408	      std::vector<ModuleId> child_modules = parent_modules;
409	      child_modules.push_back(child_module);
410	
411	      /* Set address, apply binary conversion from the first to the last element
412	       * in the address list */
413	      std::vector<char> child_addr_code = addr_code;
414	
415	      if (true == add_addr_code) {
416	        /* Find the address port from the decoder module */
417	        const ModulePortId& decoder_addr_port_id =
418	          module_manager.find_module_port(
419	            decoder_module, std::string(DECODER_ADDRESS_PORT_NAME));
420	        const BasicPort& decoder_addr_port =
421	          module_manager.module_port(decoder_module, decoder_addr_port_id);
422	        std::vector<char> addr_bits_vec =
423	          itobin_charvec(child_id, decoder_addr_port.get_width());
424	
425	        /* For top-level module, the child address should be added to the tail
426	         * For other modules, the child address should be added to the head
427	         */
428	        if (top_module == parent_module) {
429	          child_addr_code.insert(child_addr_code.end(), addr_bits_vec.begin(),
430	                                 addr_bits_vec.end());
431	        } else {
432	          VTR_ASSERT_SAFE(top_module != parent_module);
433	          child_addr_code.insert(child_addr_code.begin(), addr_bits_vec.begin(),
434	                                 addr_bits_vec.end());
435	        }
436	
437	        /* Note that the address port size of the child module may be smaller
438	         * than the maximum of other child modules at this level. We will add
439	         * dummy '0's to the head of addr_bit_vec.
440	         *
441	         * For example:
442	         *  Decoder is the decoder to access all the child modules
443	         *  whose address is decoded by the addr_bits_vec
444	         *  The child modules may use part of the address lines,
445	         *  we should add dummy '0' to fill the gap
446	         *
447	         *  Addr_code for child[0]: '000' + addr_bits_vec
448	         *  Addr_code for child[1]: '00'  + addr_bits_vec
449	         *  Addr_code for child[2]: '0' + addr_bits_vec
450	         *
451	         *                   Addr[6:8]
452	         *                     |
453	         *                     v
454	         *  +-------------------------------------------+
455	         *  |            Decoder Module                 |
456	         *  +-------------------------------------------+
457	         *
458	         *     Addr[0:2]       Addr[0:3]        Addr[0:4]
459	         *        |                |               |
460	         *        v                v               v
461	         * +-----------+  +-------------+  +------------+
462	         * | Child[0]  |  |  Child[1]   |  |  Child[2]  |
463	         * +-----------+  +-------------+  +------------+
464	         *
465	         * Child[2] has the maximum address lines among the children
466	         *
467	         */
468	        const ModulePortId& child_addr_port_id =
469	          module_manager.find_module_port(
470	            child_module, std::string(DECODER_ADDRESS_PORT_NAME));
471	        const BasicPort& child_addr_port =
472	          module_manager.module_port(child_module, child_addr_port_id);
473	        if (0 < max_child_addr_code_size - child_addr_port.get_width()) {
474	          /* Deposit don't care state for the dummy bits */
475	          std::vector<char> dummy_codes(
476	            max_child_addr_code_size - child_addr_port.get_width(),
477	            bitstream_dont_care_char);
478	          child_addr_code.insert(child_addr_code.begin(), dummy_codes.begin(),
479	                                 dummy_codes.end());
480	        }
481	      }
482	
483	      /* Go recursively */
484	      rec_build_module_fabric_dependent_frame_bitstream(
485	        bitstream_manager, child_blocks, module_manager, top_module,
486	        config_region, child_modules, child_addr_code, bitstream_dont_care_char,
487	        fabric_bitstream, fabric_bitstream_region);
488	    }
489	    /* Ensure that there should be no configuration bits in the parent block */
490	    VTR_ASSERT(0 == bitstream_manager.block_bits(parent_block).size());
491	
492	    return;
493	  }
494	
495	  /* Note that, reach here, it means that this is a leaf node.
496	   * A leaf node (a memory module) always has a decoder inside
497	   * which is the last of configurable children.
498	   * We will find the address bit and add it to addr_code
499	   * Then we can add the configuration bits to the fabric_bitstream.
500	   */
501	  std::vector<ModuleId> configurable_children;
502	  if (top_module == parent_modules.back()) {
503	    configurable_children = module_manager.region_configurable_children(
504	      parent_modules.back(), config_region);
505	  } else {
506	    VTR_ASSERT(top_module != parent_modules.back());
507	    configurable_children = module_manager.configurable_children(
508	      parent_modules.back(), ModuleManager::e_config_child_type::PHYSICAL);
509	  }
510	
511	  ModuleId decoder_module = configurable_children.back();
512	  /* Find the address port from the decoder module */
513	  const ModulePortId& decoder_addr_port_id = module_manager.find_module_port(
514	    decoder_module, std::string(DECODER_ADDRESS_PORT_NAME));
515	  const BasicPort& decoder_addr_port =
516	    module_manager.module_port(decoder_module, decoder_addr_port_id);
517	
518	  for (size_t ibit = 0;
519	       ibit < bitstream_manager.block_bits(parent_blocks.back()).size();
520	       ++ibit) {
521	    ConfigBitId config_bit =
522	      bitstream_manager.block_bits(parent_blocks.back())[ibit];
523	    std::vector<char> addr_bits_vec =
524	      itobin_charvec(ibit, decoder_addr_port.get_width());
525	
526	    std::vector<char> child_addr_code = addr_code;
527	
528	    child_addr_code.insert(child_addr_code.begin(), addr_bits_vec.begin(),
529	                           addr_bits_vec.end());
530	
531	    const FabricBitId& fabric_bit = fabric_bitstream.add_bit(config_bit);
532	
533	    /* Set address */
534	    fabric_bitstream.set_bit_address(fabric_bit, child_addr_code);
535	
536	    /* Set data input */
537	    fabric_bitstream.set_bit_din(fabric_bit,
538	                                 bitstream_manager.bit_value(config_bit));
539	
540	    /* Add the bit to the region */
541	    fabric_bitstream.add_bit_to_region(fabric_bitstream_region, fabric_bit);
542	  }
543	}
544	
545	/********************************************************************
546	 * Main function to build a fabric-dependent bitstream
547	 * by considering the configuration protocol types
548	 *******************************************************************/
549	static void build_module_fabric_dependent_bitstream(
550	  const ConfigProtocol& config_protocol, const CircuitLibrary& circuit_lib,
551	  const BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
552	  const ModuleManager& module_manager, const ModuleId& top_module,
553	  FabricBitstream& fabric_bitstream, const bool& verbose) {
554	  switch (config_protocol.type()) {
555	    case CONFIG_MEM_STANDALONE: {
556	      /* Reserve bits before build-up */
557	      fabric_bitstream.reserve_bits(bitstream_manager.num_bits());
558	
559	      for (const ConfigRegionId& config_region :
560	           module_manager.regions(top_module)) {
561	        FabricBitRegionId fabric_bitstream_region =
562	          fabric_bitstream.add_region();
563	        rec_build_module_fabric_dependent_chain_bitstream(
564	          bitstream_manager, top_block, module_manager, top_module, top_module,
565	          config_region, fabric_bitstream, fabric_bitstream_region, verbose);
566	      }
567	
568	      break;
569	    }
570	    case CONFIG_MEM_SCAN_CHAIN: {
571	      /* Reserve bits before build-up */
572	      fabric_bitstream.reserve_bits(bitstream_manager.num_bits());
573	
574	      for (const ConfigRegionId& config_region :
575	           module_manager.regions(top_module)) {
576	        FabricBitRegionId fabric_bitstream_region =
577	          fabric_bitstream.add_region();
578	        rec_build_module_fabric_dependent_chain_bitstream(
579	          bitstream_manager, top_block, module_manager, top_module, top_module,
580	          config_region, fabric_bitstream, fabric_bitstream_region, verbose);
581	        fabric_bitstream.reverse_region_bits(fabric_bitstream_region);
582	      }
583	      break;
584	    }
585	    case CONFIG_MEM_MEMORY_BANK: {
586	      /* Find global BL address port size */
587	      ModulePortId bl_addr_port = module_manager.find_module_port(
588	        top_module, std::string(DECODER_BL_ADDRESS_PORT_NAME));
589	      BasicPort bl_addr_port_info =
590	        module_manager.module_port(top_module, bl_addr_port);
591	
592	      /* Find global WL address port size */
593	      ModulePortId wl_addr_port = module_manager.find_module_port(
594	        top_module, std::string(DECODER_WL_ADDRESS_PORT_NAME));
595	      BasicPort wl_addr_port_info =
596	        module_manager.module_port(top_module, wl_addr_port);
597	
598	      /* Reserve bits before build-up */
599	      fabric_bitstream.set_use_address(true);
600	      fabric_bitstream.set_use_wl_address(true);
601	      fabric_bitstream.set_bl_address_length(bl_addr_port_info.get_width());
602	      fabric_bitstream.set_wl_address_length(wl_addr_port_info.get_width());
603	      fabric_bitstream.reserve_bits(bitstream_manager.num_bits());
604	
605	      /* Build bitstreams by region */
606	      for (const ConfigRegionId& config_region :
607	           module_manager.regions(top_module)) {
608	        size_t cur_mem_index = 0;
609	
610	        /* Find port information for local BL and WL decoder in this region */
611	        std::vector<ModuleId> configurable_children =
612	          module_manager.region_configurable_children(top_module,
613	                                                      config_region);
614	        VTR_ASSERT(2 <= configurable_children.size());
615	        ModuleId bl_decoder_module =
616	          configurable_children[configurable_children.size() - 2];
617	        ModuleId wl_decoder_module =
618	          configurable_children[configurable_children.size() - 1];
619	
620	        ModulePortId bl_port = module_manager.find_module_port(
621	          bl_decoder_module, std::string(DECODER_DATA_OUT_PORT_NAME));
622	        BasicPort bl_port_info =
623	          module_manager.module_port(bl_decoder_module, bl_port);
624	
625	        ModulePortId wl_port = module_manager.find_module_port(
626	          wl_decoder_module, std::string(DECODER_DATA_OUT_PORT_NAME));
627	        BasicPort wl_port_info =
628	          module_manager.module_port(wl_decoder_module, wl_port);
629	
630	        /* Build the bitstream for all the blocks in this region */
631	        FabricBitRegionId fabric_bitstream_region =
632	          fabric_bitstream.add_region();
633	        rec_build_module_fabric_dependent_memory_bank_bitstream(
634	          bitstream_manager, top_block, module_manager, top_module, top_module,
635	          config_region, bl_addr_port_info.get_width(),
636	          wl_addr_port_info.get_width(), bl_port_info.get_width(),
637	          wl_port_info.get_width(), cur_mem_index, fabric_bitstream,
638	          fabric_bitstream_region);
639	      }
640	      break;
641	    }
642	    case CONFIG_MEM_QL_MEMORY_BANK: {
643	      build_module_fabric_dependent_bitstream_ql_memory_bank(
644	        config_protocol, circuit_lib, bitstream_manager, top_block,
645	        module_manager, top_module, fabric_bitstream);
646	      break;
647	    }
648	    case CONFIG_MEM_FRAME_BASED: {
649	      /* Find address port size */
650	      ModulePortId addr_port = module_manager.find_module_port(
651	        top_module, std::string(DECODER_ADDRESS_PORT_NAME));
652	      BasicPort addr_port_info =
653	        module_manager.module_port(top_module, addr_port);
654	
655	      /* Reserve bits before build-up */
656	      fabric_bitstream.set_use_address(true);
657	      fabric_bitstream.reserve_bits(bitstream_manager.num_bits());
658	      fabric_bitstream.set_address_length(addr_port_info.get_width());
659	
660	      /* Avoid use don't care if there is only a region */
661	      char bitstream_dont_care_char = DONT_CARE_CHAR;
662	      if (1 == module_manager.regions(top_module).size()) {
663	        bitstream_dont_care_char = '0';
664	      }
665	
666	      /* Find the maximum decoder address among all the configurable regions */
667	      size_t max_decoder_addr_size = 0;
668	      for (const ConfigRegionId& config_region :
669	           module_manager.regions(top_module)) {
670	        std::vector<ModuleId> configurable_children =
671	          module_manager.region_configurable_children(top_module,
672	                                                      config_region);
673	        /* Bypass the regions that have no decoders */
674	        if ((0 == configurable_children.size()) ||
675	            (1 == configurable_children.size())) {
676	          continue;
677	        }
678	        ModuleId decoder_module = configurable_children.back();
679	        ModulePortId decoder_addr_port_id = module_manager.find_module_port(
680	          decoder_module, DECODER_ADDRESS_PORT_NAME);
681	        BasicPort decoder_addr_port =
682	          module_manager.module_port(decoder_module, decoder_addr_port_id);
683	        max_decoder_addr_size =
684	          std::max(max_decoder_addr_size, decoder_addr_port.get_width());
685	      }
686	
687	      for (const ConfigRegionId& config_region :
688	           module_manager.regions(top_module)) {
689	        std::vector<ModuleId> configurable_children =
690	          module_manager.region_configurable_children(top_module,
691	                                                      config_region);
692	
693	        /* Bypass non-configurable regions */
694	        if (0 == configurable_children.size()) {
695	          continue;
696	        }
697	
698	        /* Find the idle address bit which should be added to the head of the
699	         * address bit This depends on the number of address bits required by
700	         * this region For example: Top-level address is addr[0:4] There are 4
701	         * decoders in the top-level module, whose address sizes are decoder A:
702	         * addr[0:4] decoder B: addr[0:3] decoder C: addr[0:2] decoder D:
703	         * addr[0:3] For decoder A, the address fit well For decoder B, an idle
704	         * bit should be added '0' + addr[0:3] For decoder C, two idle bits
705	         * should be added '00' + addr[0:2] For decoder D, an idle bit should be
706	         * added '0' + addr[0:3]
707	         */
708	        ModuleId decoder_module = configurable_children.back();
709	        ModulePortId decoder_addr_port_id = module_manager.find_module_port(
710	          decoder_module, DECODER_ADDRESS_PORT_NAME);
711	        BasicPort decoder_addr_port =
712	          module_manager.module_port(decoder_module, decoder_addr_port_id);
713	        VTR_ASSERT(max_decoder_addr_size >= decoder_addr_port.get_width());
714	        std::vector<char> idle_addr_bits(
715	          max_decoder_addr_size - decoder_addr_port.get_width(),
716	          bitstream_dont_care_char);
717	
718	        FabricBitRegionId fabric_bitstream_region =
719	          fabric_bitstream.add_region();
720	        rec_build_module_fabric_dependent_frame_bitstream(
721	          bitstream_manager, std::vector<ConfigBlockId>(1, top_block),
722	          module_manager, top_module, config_region,
723	          std::vector<ModuleId>(1, top_module), idle_addr_bits,
724	          bitstream_dont_care_char, fabric_bitstream, fabric_bitstream_region);
725	      }
726	      break;
727	    }
728	    default:
729	      VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid SRAM organization.\n");
730	      exit(1);
731	  }
732	
733	  /* Time-consuming sanity check: Uncomment these codes only for debugging!!!
734	   * Check which configuration bits are not touched
735	   */
736	  /*
737	  for (const ConfigBitId& config_bit : bitstream_manager.bits()) {
738	    std::vector<ConfigBitId>::iterator it = std::find(fabric_bitstream.begin(),
739	  fabric_bitstream.end(), config_bit); if (it == fabric_bitstream.end()) {
740	      std::vector<ConfigBlockId> block_hierarchy =
741	  find_bitstream_manager_block_hierarchy(bitstream_manager,
742	  bitstream_manager.bit_parent_block(config_bit)); std::string
743	  block_hierarchy_name; for (const ConfigBlockId& temp_block : block_hierarchy)
744	  { block_hierarchy_name += std::string("/") +
745	  bitstream_manager.block_name(temp_block);
746	      }
747	      vpr_printf(TIO_MESSAGE_INFO,
748	                 "bit (parent_block = %s) is not touched!\n",
749	                 block_hierarchy_name.c_str());
750	    }
751	  }
752	   */
753	
754	  /* Ensure our fabric bitstream is in the same size as device bistream */
755	  VTR_ASSERT(bitstream_manager.num_bits() == fabric_bitstream.num_bits());
756	}
