758	/********************************************************************
759	 * A top-level function re-organizes the bitstream for a specific
760	 * FPGA fabric, where configuration bits are organized in the sequence
761	 * that can be directly loaded to the FPGA configuration protocol.
762	 * Support:
763	 * 1. Configuration chain
764	 * 2. Memory decoders
765	 * This function does NOT modify the bitstream database
766	 * Instead, it builds a vector of ids for configuration bits in bitstream
767	 *manager
768	 *
769	 * This function can be called ONLY after the function build_device_bitstream()
770	 * Note that this function does NOT decode bitstreams from circuit
771	 *implementation It was done in the function build_device_bitstream()
772	 *******************************************************************/
773	FabricBitstream build_fabric_dependent_bitstream(
774	  const BitstreamManager& bitstream_manager,
775	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
776	  const CircuitLibrary& circuit_lib, const ConfigProtocol& config_protocol,
777	  const bool& verbose) {
778	  FabricBitstream fabric_bitstream;
779	
780	  vtr::ScopedStartFinishTimer timer("\nBuild fabric dependent bitstream\n");
781	
782	  /* Get the top module name in module manager, which is our starting point */
783	  std::string top_module_name =
784	    module_name_map.name(generate_fpga_top_module_name());
785	  ModuleId top_module = module_manager.find_module(top_module_name);
786	  VTR_ASSERT(true == module_manager.valid_module_id(top_module));
787	
788	  /* Find the top block in bitstream manager, which has not parents */
789	  std::vector<ConfigBlockId> top_blocks =
790	    find_bitstream_manager_top_blocks(bitstream_manager);
791	  /* Make sure we have only 1 top block and its name matches the top module */
792	  VTR_ASSERT(1 == top_blocks.size());
793	  VTR_ASSERT(
794	    0 == top_module_name.compare(bitstream_manager.block_name(top_blocks[0])));
795	  ConfigBlockId top_block = top_blocks[0];
796	
797	  /* Create the core block when the fpga_core is added */
798	  std::string core_block_name = generate_fpga_core_module_name();
799	  if (module_name_map.name_exist(core_block_name)) {
800	    core_block_name = module_name_map.name(core_block_name);
801	  }
802	  const ModuleId& core_module = module_manager.find_module(core_block_name);
803	  if (module_manager.valid_module_id(core_module)) {
804	    /* Now we use the core_block as the top-level block for the remaining
805	     * functions */
806	    VTR_ASSERT(bitstream_manager.block_children(top_block).size() == 1);
807	    ConfigBlockId core_block = bitstream_manager.block_children(top_block)[0];
808	    top_module = core_module;
809	    top_block = core_block;
810	  }
811	
812	  /* Start build-up formally */
813	  build_module_fabric_dependent_bitstream(
814	    config_protocol, circuit_lib, bitstream_manager, top_block, module_manager,
815	    top_module, fabric_bitstream, verbose);
816	
817	  VTR_LOGV(verbose, "Built %lu configuration bits for fabric\n",
818	           fabric_bitstream.num_bits());
819	
820	  return fabric_bitstream;
821	}
822	
823	} /* end namespace openfpga */
