260	    find_path_dir_name(cmd_context.option_value(cmd, opt_file));
261	
262	  /* Create directories */
263	  create_directory(src_dir_path, true, true);
264	
265	  /* Default depth requirement, this is to limit the report size by default */
266	  int depth = 1;
267	  CommandOptionId opt_depth = cmd.option("depth");
268	  if (true == cmd_context.option_enable(cmd, opt_depth)) {
269	    depth = std::atoi(cmd_context.option_value(cmd, opt_depth).c_str());
270	    /* Error out if we have negative depth */
271	    if (0 > depth) {
272	      VTR_LOG_ERROR(
273	        "Invalid depth '%d' which should be 0 or a positive number!\n", depth);
274	      return CMD_EXEC_FATAL_ERROR;
275	    }
276	  }
277	
278	  status = report_bitstream_distribution(
279	    cmd_context.option_value(cmd, opt_file), openfpga_ctx.bitstream_manager(),
280	    openfpga_ctx.fabric_bitstream(),
281	    !cmd_context.option_enable(cmd, opt_no_time_stamp), depth);
282	
283	  return status;
